import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.DnrXFDHb.js";const o=JSON.parse('{"title":"F09: 毛利變動與經營槓桿審計 - finance-financial-analyst 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F09_毛利變動與經營槓桿審計.md","filePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F09_毛利變動與經營槓桿審計.md"}'),n={name:"審計報告庫/財務審計/8103_瀚荃/20260425/F09_毛利變動與經營槓桿審計.md"};function i(s,t,r,f,g,x){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="f09-毛利變動與經營槓桿審計-finance-financial-analyst-審計報告" tabindex="-1">F09: 毛利變動與經營槓桿審計 - finance-financial-analyst 審計報告 <a class="header-anchor" href="#f09-毛利變動與經營槓桿審計-finance-financial-analyst-審計報告" aria-label="Permalink to &quot;F09: 毛利變動與經營槓桿審計 - finance-financial-analyst 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>毛利率 (GM)、營業利益率 (OPM) 與淨利率的連動關係為何？是否存在經營槓桿 (Operating Leverage) 放大或侵蝕損益的現象？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>瀚荃八季毛利率從 31.7% 升至 39.1%（AI 佔比提升），營益率 6.9%-16.5% 震盪（波動 960 bps），DOL 跳升至 4.43，槓桿顯著。淨利率受業外扭曲。評級 <strong>A（良）</strong>：產品組合優化帶動毛利向上，惟營費率波動及業外干擾需監控。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>A（良）</strong></p><ul><li>毛利率連續四季攀升（31.7%→39.1%），顯示 AI 連接器的結構性定價保護</li><li>營益率在 6.9%-16.5% 間大幅擺動，經營槓桿效應顯著</li><li>淨利率受業外損益嚴重干擾（2024Q3 業外虧損 6,303 萬、2024Q4 業外收益 7,581 萬），本業獲利含金量需剔除業外後評估</li><li>營費率在 21.3%-27.6% 間波動，2025Q4 跳升至 27.6% 需關注是否為擴產前置投入</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、三率連動趨勢-近八季" tabindex="-1">一、三率連動趨勢（近八季） <a class="header-anchor" href="#一、三率連動趨勢-近八季" aria-label="Permalink to &quot;一、三率連動趨勢（近八季）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">季度</th><th style="text-align:left;">營收(百萬)</th><th style="text-align:left;">毛利率</th><th style="text-align:left;">營益率</th><th style="text-align:left;">淨利率</th><th style="text-align:left;">營費率</th><th style="text-align:left;">業外佔稅前比</th></tr></thead><tbody><tr><td style="text-align:left;">2024Q1</td><td style="text-align:left;">673</td><td style="text-align:left;">31.7%</td><td style="text-align:left;">6.3%</td><td style="text-align:left;">12.4%</td><td style="text-align:left;">25.4%</td><td style="text-align:left;">65.0%</td></tr><tr><td style="text-align:left;">2024Q2</td><td style="text-align:left;">803</td><td style="text-align:left;">38.7%</td><td style="text-align:left;">15.5%</td><td style="text-align:left;">14.2%</td><td style="text-align:left;">23.3%</td><td style="text-align:left;">28.1%</td></tr><tr><td style="text-align:left;">2024Q3</td><td style="text-align:left;">883</td><td style="text-align:left;">36.8%</td><td style="text-align:left;">16.0%</td><td style="text-align:left;">6.2%</td><td style="text-align:left;">20.9%</td><td style="text-align:left;">-80.9%</td></tr><tr><td style="text-align:left;">2024Q4</td><td style="text-align:left;">829</td><td style="text-align:left;">31.2%</td><td style="text-align:left;">6.9%</td><td style="text-align:left;">10.3%</td><td style="text-align:left;">24.3%</td><td style="text-align:left;">57.0%</td></tr><tr><td style="text-align:left;">2025Q1</td><td style="text-align:left;">738</td><td style="text-align:left;">34.2%</td><td style="text-align:left;">9.0%</td><td style="text-align:left;">9.2%</td><td style="text-align:left;">25.1%</td><td style="text-align:left;">27.3%</td></tr><tr><td style="text-align:left;">2025Q2</td><td style="text-align:left;">851</td><td style="text-align:left;">37.5%</td><td style="text-align:left;">16.5%</td><td style="text-align:left;">4.6%</td><td style="text-align:left;">21.0%</td><td style="text-align:left;">-54.1%</td></tr><tr><td style="text-align:left;">2025Q3</td><td style="text-align:left;">874</td><td style="text-align:left;">38.3%</td><td style="text-align:left;">16.0%</td><td style="text-align:left;">13.2%</td><td style="text-align:left;">22.4%</td><td style="text-align:left;">12.2%</td></tr><tr><td style="text-align:left;">2025Q4</td><td style="text-align:left;">892</td><td style="text-align:left;">39.1%</td><td style="text-align:left;">11.6%</td><td style="text-align:left;">13.1%</td><td style="text-align:left;">27.6%</td><td style="text-align:left;">27.9%</td></tr></tbody></table><p><strong>三率核心發現</strong>：(1) 毛利率累計提升 740 bps（31.7%→39.1%），與 AI 產品佔比從 5% 升至 18% 吻合，AI 連接器 ASP 與毛利顯著優於傳統產品。(2) 營益率波動 960 bps，2024Q4 營收僅降 6.1%，營益率卻縮水 910 bps，固定成本侵蝕效應顯著。(3) 淨利率受業外嚴重扭曲（2024Q3 業外虧 6,303 萬使淨利率僅 6.2%，遠低於營益率 16.0%；2025Q2 業外虧 4,925 萬壓抑淨利至 4.6%），應以營益率作為核心獲利指標。</p><h3 id="二、費用侵蝕臨界審查" tabindex="-1">二、費用侵蝕臨界審查 <a class="header-anchor" href="#二、費用侵蝕臨界審查" aria-label="Permalink to &quot;二、費用侵蝕臨界審查&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">季度</th><th style="text-align:left;">營費率</th><th style="text-align:left;">費用變動</th></tr></thead><tbody><tr><td style="text-align:left;">2024Q1</td><td style="text-align:left;">25.4%</td><td style="text-align:left;">基期</td></tr><tr><td style="text-align:left;">2024Q2</td><td style="text-align:left;">23.3%</td><td style="text-align:left;">-2.1pp</td></tr><tr><td style="text-align:left;">2024Q3</td><td style="text-align:left;">20.9%</td><td style="text-align:left;">-2.4pp</td></tr><tr><td style="text-align:left;">2024Q4</td><td style="text-align:left;">24.3%</td><td style="text-align:left;">+3.4pp</td></tr><tr><td style="text-align:left;">2025Q1</td><td style="text-align:left;">25.1%</td><td style="text-align:left;">+0.8pp</td></tr><tr><td style="text-align:left;">2025Q2</td><td style="text-align:left;">21.0%</td><td style="text-align:left;">-4.1pp</td></tr><tr><td style="text-align:left;">2025Q3</td><td style="text-align:left;">22.4%</td><td style="text-align:left;">+1.4pp</td></tr><tr><td style="text-align:left;">2025Q4</td><td style="text-align:left;">27.6%</td><td style="text-align:left;">+5.2pp</td></tr></tbody></table><p>2025Q4 營費率跳升至 27.6%（營業費用 2.46 億），季增 5,044 萬（+25.8%），營收僅增 2.0%。此即**「低效擴張風險訊號」**——擴建泰國廠、研發投入及行銷提前燒錢。若未回落至 22-24%，燒錢擴產判斷成立。</p><h3 id="三、經營槓桿效率檢驗-季對季-dol" tabindex="-1">三、經營槓桿效率檢驗（季對季 DOL） <a class="header-anchor" href="#三、經營槓桿效率檢驗-季對季-dol" aria-label="Permalink to &quot;三、經營槓桿效率檢驗（季對季 DOL）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">期間</th><th style="text-align:left;">營收變動%</th><th style="text-align:left;">營益變動%</th><th style="text-align:left;">DOL</th></tr></thead><tbody><tr><td style="text-align:left;">2024Q1→Q2</td><td style="text-align:left;">+19.2%</td><td style="text-align:left;">+194.1%</td><td style="text-align:left;">10.11</td></tr><tr><td style="text-align:left;">2024Q2→Q3</td><td style="text-align:left;">+10.0%</td><td style="text-align:left;">+13.5%</td><td style="text-align:left;">1.35</td></tr><tr><td style="text-align:left;">2024Q3→Q4</td><td style="text-align:left;">-6.1%</td><td style="text-align:left;">-59.5%</td><td style="text-align:left;">9.75</td></tr><tr><td style="text-align:left;">2024Q4→2025Q1</td><td style="text-align:left;">-11.0%</td><td style="text-align:left;">+16.5%</td><td style="text-align:left;">-1.50*</td></tr><tr><td style="text-align:left;">2025Q1→Q2</td><td style="text-align:left;">+15.3%</td><td style="text-align:left;">+110.6%</td><td style="text-align:left;">7.23</td></tr><tr><td style="text-align:left;">2025Q2→Q3</td><td style="text-align:left;">+2.7%</td><td style="text-align:left;">-0.3%</td><td style="text-align:left;">-0.11</td></tr><tr><td style="text-align:left;">2025Q3→Q4</td><td style="text-align:left;">+2.0%</td><td style="text-align:left;">-26.3%</td><td style="text-align:left;">-13.15</td></tr></tbody></table><p>*2024Q4→2025Q1 營收降但營益升，因 2024Q4 含大額業外收益致稅前淨利虛高。</p><p>DOL 高達 7-10 倍，每增 1% 營收帶動 7-10% 營益增幅（正向槓桿收割期）；回落時營益可暴跌 60%。非線性特徵源自固定成本（折舊、薪資、廠房）佔比較高，產能利用率在 70-85% 間震盪。</p><h3 id="四、定價權與同業對比" tabindex="-1">四、定價權與同業對比 <a class="header-anchor" href="#四、定價權與同業對比" aria-label="Permalink to &quot;四、定價權與同業對比&quot;">​</a></h3><p>瀚荃 2025Q4 毛利率 39.1% 高於連接器同業中位值（宏致 27%、正淩 25%）5% 以上，具備 AI 伺服器客製化溢價帶來的<strong>結構性定價保護</strong>，非價格競爭型業者。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>核心洞察——「技術開道」而非「補貼換盤」</strong>：</p><p>瀚荃的毛利率上升與研發投入高度正相關。公司 2025 年前 11 月 AI 產品營收佔比從 5% 升至 18%，這不是靠壓低價格搶單，而是靠高階板端電源連接器的技術壁壘——PSU 需 5 塊板、BBU 需 2-3 塊、CDU 更多，每塊板都需要瀚荃的高瓦數連接器，ASP 與毛利率均顯著提升。這是「技術開道」的典型特徵。</p><p><strong>風險警示</strong>：</p><ol><li>2025Q4 營費率 27.6% 的暴增若持續超過兩季，將從「擴產前置投入」轉為「管理效能遞減」訊號</li><li>業外損益的劇烈波動（匯兌、金融資產評價）使淨利率失真，投資者切勿以淨利判斷瀚荃的獲利品質</li><li>若 AI 伺服器需求降溫，毛利率可能從 39% 回落至 32-34%（一般伺服器毛利水準），疊加經營槓桿效應，營益率可能腰斬至 6-8%</li></ol><p><strong>物理對策</strong>：追蹤 2026Q1-Q2 營費率是否回落至 23% 以下；監控 AI 產品營收佔比是否維持 15% 以上；關注匯率避險政策是否降低業外波動。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ol><li><strong>FinMind 損益表</strong>：finance alias，提取 Revenue、CostOfGoodsSold、GrossProfit、OperatingExpenses、OperatingIncome、NetIncome 等科目，查詢區間 2023-04-25 至 2026-04-25</li><li><strong>FinMind 現金流量表</strong>：cash_flow alias，提取 Depreciation 及 AmortizationExpense 供經營槓桿分析</li><li><strong>富果法說會摘要 (2025/12/12)</strong>：確認 AI 產品營收佔比 18%、產品組合優化方向、PSU/BBU/CDU 連接器用量邏輯</li><li><strong>Python 計算腳本</strong>：/tmp/8103_audit_calc.py，執行三率連動計算、季對季 DOL 及年度 DOL 估算</li><li><strong>同業毛利率對比</strong>：宏致(3605)、正淩(3143) 2024 年度財報數據</li></ol>',29)])])}const h=e(n,[["render",i]]);export{o as __pageData,h as default};
